+            ("bead", "bd-2qbx.6"),
+        ],
+    );
+
+    let iterations = 200usize;
+    let mut times_us = Vec::with_capacity(iterations);
+
+    for i in 0..iterations {
+        // Simulate different contexts by toggling show_context
+        let show_ctx = i % 2 == 0;
+        let hints = sample_hints()
+            .with_show_context(show_ctx)
+            .with_key_format(if i % 3 == 0 {
+                KeyFormat::Bracketed
+            } else {
+                KeyFormat::Plain
+            });
+
+        let start = Instant::now();
+        let (_frame, _hash) = render_hints(&hints, 80, 20);
+        let elapsed = start.elapsed().as_micros() as u64;
+        times_us.push(elapsed);
+    }
+
+    times_us.sort();
+    let p50 = times_us[times_us.len() / 2];
+    let p95 = times_us[(times_us.len() as f64 * 0.95) as usize];
+    let p99 = times_us[(times_us.len() as f64 * 0.99) as usize];
+
+    log_jsonl(
+        "perf_summary",
