+            ("iterations", &iterations.to_string()),
+            ("p50_us", &p50.to_string()),
+            ("p95_us", &p95.to_string()),
+            ("p99_us", &p99.to_string()),
+        ],
+    );
+
+    // Budget: keep p95 under 2ms for context switches
+    assert!(p95 <= 2000, "p95 context switch too slow: {p95}us");
